    // These calculations are kept for structural similarity, but their direct impact on kernel launch is gone.
    global_num_blocks_perdim = sqrt((double) npoints / THREADS_PER_DIM); // Approximation
    while (global_num_blocks_perdim * global_num_blocks_perdim < npoints / THREADS_PER_DIM)
        global_num_blocks_perdim++;

    global_num_threads_perdim = THREADS_PER_DIM;
    global_num_threads = global_num_threads_perdim * global_num_threads_perdim;
    global_num_blocks = global_num_blocks_perdim * global_num_blocks_perdim;

