/* This kernel was responsible for calculating distances, assigning memberships,
   and potentially accumulating sums for new centers and deltas.
   In OpenMP, this logic will be implemented within loops with pragmas. */
void kmeansPoint_openmp(float  *features,
                        int     nfeatures,
                        int     npoints,
                        int     nclusters,
                        int    *membership,
                        float  *clusters,
                        float  *block_clusters, // Not used in this OpenMP translation
                        int    *block_deltas)   // Not used in this OpenMP translation
{
    int delta = 0;
    int i, j;

    // Initialize block_new_centers_host for summation
    memset(block_new_centers_host, 0, nclusters * nfeatures * sizeof(float));

    // Parallel loop for calculating distances and assigning memberships
    #pragma omp parallel for \
        shared(features, clusters, membership, block_new_centers_host) \
        private(i, j) \
        firstprivate(nfeatures, npoints, nclusters) \
        schedule(static)
    for (i = 0; i < npoints; i++)
    {
        int cluster_id = -1;
        float min_dist = FLT_MAX;
        float dist;

        for (j = 0; j < nclusters; j++)
        {
            float ans = 0.0;
            for (int k = 0; k < nfeatures; k++)
            {
                float diff = (features[i * nfeatures + k] - clusters[j * nfeatures + k]);
                ans += diff * diff;
            }
            dist = ans;

            if (dist < min_dist)
            {
                min_dist = dist;
                cluster_id = j;
            }
        }

        // Update membership and accumulate for new centers
        membership[i] = cluster_id;

        // Accumulate sums for new centers
        if (cluster_id != -1) {
            for (int k = 0; k < nfeatures; k++) {
                block_new_centers_host[cluster_id * nfeatures + k] += features[i * nfeatures + k];
            }
        }
    }

    // Calculate delta (number of points that changed cluster)
    // This part was handled by a separate loop in the CUDA version after copying back membership_d.
    // We can do it here by comparing the new membership with the old one.
    // However, the original CUDA code copies membership_new (which is the result of the kernel)
    // back to membership_new_host and then compares it with the original 'membership' array.
    // To replicate that, we'll do the delta calculation in the main kmeansCuda function.
}


