/* This function orchestrates the K-means clustering process.
   It was the host-side driver for CUDA kernels.
   Now it will manage OpenMP parallel regions and calls to the OpenMP equivalent kernel. */
int kmeansCuda(float  **feature,             /* in: [npoints][nfeatures] */
               int      nfeatures,           /* number of attributes for each point */
               int      npoints,             /* number of data points */
               int      nclusters,           /* number of clusters */
               int     *membership,          /* which cluster the point belongs to */
               float  **clusters,            /* coordinates of cluster centers */
               int     *new_centers_len,     /* number of elements in each cluster */
               float  **new_centers          /* sum of elements in each cluster */
               )
{
    int delta = 0;
    int i, j;

    // Store global variables
    global_npoints = npoints;
    global_nfeatures = nfeatures;
    global_nclusters = nclusters;

    // Allocate memory (this part is similar to CUDA's allocateMemory but for host)
    // Re-using allocateMemory for consistency, though it's now host-only.
    // Note: The original CUDA allocateMemory also handled device allocations.
    // For OpenMP, we assume memory is already allocated or managed by the caller.
    // We will allocate necessary host-side buffers here if they are not passed in.

    // Initialize membership_new_host if it's the first iteration or if it needs resetting
    // The original CUDA code initializes membership_new to -1.
    // This is typically done before the first call to kmeansCuda.
    // For subsequent calls, membership_new_host will be updated by the kernel.
    if (membership_new_host == NULL) {
        membership_new_host = (int*) malloc(npoints * sizeof(int));
        for(int k=0; k<npoints; k++) {
            membership_new_host[k] = -1;
        }
    }

    // Copy clusters to host memory if they are not already there (they are passed by reference)
    // The 'clusters' parameter is already a host pointer.

    // The texture binding and constant memory copy are CUDA specific and not needed for OpenMP.

    // Call the OpenMP equivalent of the kmeansPoint kernel
    // The original CUDA kernel was launched with <<< grid, threads >>>.
    // In OpenMP, the parallelism is managed by pragmas within the function.
    kmeansPoint_openmp(feature[0], // Assuming feature[0] is the contiguous array
                       nfeatures,
                       npoints,
                       nclusters,
                       membership_new_host, // This will store the new memberships
                       clusters[0],         // Assuming clusters[0] is the contiguous array
                       NULL, // block_clusters not used in this OpenMP translation
                       NULL  // block_deltas not used in this OpenMP translation
                      );

    // After the OpenMP kernel execution, membership_new_host contains the new assignments.
    // Now, we need to calculate delta and update new_centers, similar to the host-side reduction in CUDA.

    delta = 0;
    // Reset new_centers_len and new_centers for summation
    memset(new_centers_len, 0, nclusters * sizeof(int));
    memset(new_centers[0], 0, nclusters * nfeatures * sizeof(float));

    // Parallel loop to calculate delta and sum for new centers
    #pragma omp parallel for \
        shared(membership, membership_new_host, new_centers_len, new_centers, feature) \
        private(i, j) \
        firstprivate(npoints, nfeatures, nclusters) \
        schedule(static)
    for (i = 0; i < npoints; i++)
    {
        int cluster_id = membership_new_host[i];
        new_centers_len[cluster_id]++;
        if (membership_new_host[i] != membership[i])
        {
            delta++;
            membership[i] = membership_new_host[i];
        }
        // Accumulate sums for new centers
        for (j = 0; j < nfeatures; j++)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
    }

    // The block reduction parts (#ifdef BLOCK_DELTA_REDUCE, #ifdef BLOCK_CENTER_REDUCE)
    // were CUDA specific optimizations. In OpenMP, the parallel loop above
    // directly calculates the global sums for delta and new_centers.
    // The 'block_new_centers_host' is used within the kmeansPoint_openmp function
    // to accumulate sums per cluster, and then the loop above aggregates these
    // into the final 'new_centers'.

    return delta;
}

